INSERT INTO `blog_posts` (`id`, `title`, `slug`, `content`, `image`, `author`, `status`, `deleted`, `created_at`, `updated_at`, `seo_title`, `seo_description`, `seo_keywords`) VALUES
(4, 'Usos y Tips para el Tonico Capilar CapellB5', 'usos-y-tips-para-el-tonico-capilar-capellb5', '<p>Mapa 6-Zonas + Masaje 90s 🕛</p><p><br></p><p>Qué hace: Cobertura uniforme “raíz por raíz”, mejor distribución y sensación de cuero cabelludo activo.</p><p>Cómo se hace (1.5 min):</p><p><span style=\"white-space: normal;\"><span style=\"white-space:pre\">	</span>•<span style=\"white-space:pre\">	</span>Divide la cabeza en 6 zonas: frontal, coronilla, nuca y laterales (izq/der).</span></p><p><span style=\"white-space: normal;\"><span style=\"white-space:pre\">	</span>•<span style=\"white-space:pre\">	</span>Aplica 2–3 sprays por zona a 10–15 cm.</span></p><p><span style=\"white-space: normal;\"><span style=\"white-space:pre\">	</span>•<span style=\"white-space:pre\">	</span>Masajea 15 s con yemas (movimientos circulares + leves presiones).</span></p><p><span style=\"white-space: normal;\"><span style=\"white-space:pre\">	</span>•<span style=\"white-space:pre\">	</span>Finaliza con un peine de púas anchas para llevar micro-bruma a medios y puntas.</span></p><p>Pro tip: Usa un masajeador de silicona 2–3 veces por semana para potenciar la rutina sin maltratar.</p>', 'public/images/blog/1759171469_IMAGEN_PASTO.jpg', 'Luis Arias', 'published', 1, '2025-09-25 01:05:24', '2025-09-29 19:36:36', 'usos del Tónico Capell B5 que sí se sienten', 'Activa raíces, refresca post-gym y arma rutina AM/PM con el Tónico Capell B5 (11+ extractos). Tres hacks efectivos: mapa 6 zonas, reset express y frío/calma', 'tónico capilar, Capell B5, 11 extractos naturales, hacks de cabello, mapa 6 zonas, post gym hair, rutina AM PM, cuero cabelludo, crecimiento saludable, fortalecer raíces, bruma capilar, masaje capilar, romero, ortiga, quina, cola de caballo, ginseng'),
(5, 'La Paradoja del Uribismo en el Cauca: Entre la Cúpula y la Crítica Local', 'la-paradoja-del-uribismo-en-el-cauca-entre-la-cupula-y-la-critica-local', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La reciente decisión del Centro Democrático de optar por una *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">lista cerrada*</span>, promovida por Álvaro Uribe Vélez, ha desatado una notable *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">ironía*</span> en el escenario político del Cauca. Lo que se observa es una metamorfosis política: aquellos que en el pasado fueron críticos acérrimos o mantuvieron distancia del *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Uribismo*</span> hoy se presentan como los más fervientes defensores de sus banderas. *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Esta contradicción pone en evidencia una preocupante doble moral*.</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">*Aves de Rapiña y el ‘Pastel’ del Poder*</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">No *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">podemos ignorar que muchos de estos nuevos ‘conversos’ al Uribismo* </span>parecen ser simples *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«aves de rapiña»*</span> qué buscan asegurar su puesto en el tarjetón. Son individuos que han mantenido alianzas históricas con figuras y sectores de dudosa reputación, cuyo *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«inri hacia temas oscuros»*</span> es innegable.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Pretender una imagen de pureza y pavonearse como *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«impolutos»*</span> es una burla al electorado, especialmente cuando es claro que *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«también comieron de ese pastel»*</span> del clientelismo y las prácticas cuestionables del pasado. La política, una vez más, muestra su cara más oportunista, *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">donde la lealtad se compra con la cercanía al poder y no con principios firmes*.</span></p>', 'public/images/blog/1759174741_12.jpg', 'Intermedia Colombia', 'published', 0, '2025-09-29 19:39:01', '2025-09-29 19:43:49', '', '', ''),
(6, 'Cáncer de la Salud: Castigo Criminal y Reforma Estructural para la NUEVA EPS', 'cancer-de-la-salud-castigo-criminal-y-reforma-estructural-para-la-nueva-eps', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El escándalo de <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">corrupción</span> que azota a la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">NUEVA EPS</span>, la aseguradora de salud más grande del país, es más que un simple desfalco financiero. Es una afrenta directa a la vida, una traición a la confianza pública y un crimen que debe ser juzgado con la máxima severidad. El desvío de <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">$70.563 millones de pesos</span> para maquillar pérdidas y sostener contratos lucrativos no es un «error contable»; es un acto deliberado que convirtió la salud de millones de colombianos en la caja menor de intereses privados.</p><h2 style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">La Salud como Botín: Un Fraude con Víctimas Reales</h2><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"> </p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Las revelaciones de la Contraloría General de la Nación, que documentan cómo entre 2019 y 2023 se ocultaron miles de facturas y pasivos reales para simular una solvencia ficticia, pintan un panorama desolador. Esta manipulación permitió que la EPS mantuviera su habilitación regulatoria y continuara recibiendo cuantiosos giros estatales, a pesar de estar sumida en pérdidas.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Las víctimas de este fraude son fácilmente identificables: las <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Instituciones Prestadoras de Salud (IPS)</span>, que quedaron con cuentas sin cobrar, y, lo más grave, los <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">pacientes</span> que vieron en riesgo la continuidad de sus tratamientos. Cuando los fondos destinados a curar y cuidar se desvían para mantener un <i style=\"margin: 0px; padding: 0px; border: 0px; font-variant: inherit; font-weight: inherit; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">balance</i> artificial, se rompe la cadena de atención. La salud pública se convierte en un riesgo sistémico. El salto de la deuda de <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">$5.42 billones a $21.37 billones</span> en solo un año es la prueba irrefutable de un sistema colapsado por la avaricia.</p><h2 style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">Urge la Celeridad Penal y la Recuperación sin Tregua</h2>', 'public/images/blog/1759174795_eps-1032x570.jpg', 'Intermedia Colombia', 'published', 0, '2025-09-29 19:39:55', '2025-09-29 19:40:20', '', '', ''),
(7, '¿Retórica Política o Triste Realidad? La Controversia de Fico contra Petro', 'retorica-politica-o-triste-realidad-la-controversia-de-fico-contra-petro', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El escenario político colombiano se caldeó aún más con las recientes declaraciones del alcalde de Medellín, <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Federico Gutiérrez</span>, en el Congreso Nacional de Comerciantes. Al arremeter contra el presidente <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Gustavo Petro</span>, Gutiérrez no solo encendió la mecha de la polarización, sino que utilizó una frase de un impacto desgarrador: «Si Petro no hubiera sido presidente, Miguel Uribe estaría vivo». Esta afirmación, de una contundencia dramática, merece un análisis que trascienda la mera disputa electoral.</p><h2 style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">La Carga de las Palabras</h2><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"> </p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La supuesta cita sobre <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Miguel Uribe</span>, aunque aún debe ser verificada en su contexto y exactitud (dado que el senador <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Miguel Uribe Turbay</span> está vivo y es un activo opositor del gobierno), funciona como un potente <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">golpe de efecto</span> si se entiende en el contexto de la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">crítica a la seguridad</span> que muchos sectores achacan a la administración Petro. Si la frase original del alcalde se refería a una persona diferente o es una cita inexacta en el titular, el daño retórico ya está hecho. El alcalde está capitalizando el <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">descontento</span> en temas de orden público y la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">sensación de vulnerabilidad</span> que permea a la ciudadanía. La estrategia es clara: vincular directamente la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">gestión</span> del gobierno nacional con la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">pérdida de vidas</span>, la narrativa más poderosa y emocional en política.</p><h2 style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">El Horizonte 2026: Una Promesa Electoral Disfrazada de Crítica</h2><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La crítica de Gutiérrez va más allá de un simple reproche coyuntural. Su optimismo respecto a la elección de un candidato <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«diferente a la línea de Petro»</span> en <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">2026</span> no es casual. Medellín, bajo su liderazgo, se ha consolidado como un bastión de la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">oposición</span>. Al asegurar que el próximo año el presidente sí estará presente en el evento porque el electorado habrá «escogido» otro camino, Fico se posiciona no solo como alcalde, sino como un <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">potencial líder</span> y articulador de esa «otra línea» política. Es un mensaje directo a las bases empresariales de Fenalco, asegurándoles que hay una luz al final del túnel de la actual administración.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La ausencia de representación del Gobierno nacional en un evento tan relevante para el sector económico, debido a <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«serias diferencias con Fenalco»</span>, solo subraya la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">ruptura</span> entre el estamento empresarial y el ejecutivo. En este ambiente de tensión, las palabras de Gutiérrez resuenan con especial fuerza entre los comerciantes, quienes sienten que sus preocupaciones no son escuchadas por el gobierno central.</p><h2 style=\"margin: 0.83em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.953em; line-height: 1.35; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">¿Es Justo el Ataque?</h2><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Si bien es legítimo y necesario criticar la gestión gubernamental, especialmente en aspectos sensibles como la economía y la seguridad, la pregunta es si la retórica empleada por Gutiérrez es <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">constructiva</span> o meramente <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">incendiaria</span>.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">A favor del alcalde:</span> La oposición tiene el deber de señalar las fallas. El desinterés del gobierno por dialogar con gremios como Fenalco puede interpretarse como una cerrazón que afecta la estabilidad del país.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">En contra de la retórica:</span> Utilizar la tragedia o una referencia a la muerte como arma política, si bien es una técnica antigua, corre el riesgo de caer en el <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">populismo emotivo</span>. La complejidad de la seguridad y el crimen no puede simplificarse a la mera presencia o ausencia de un presidente; es un problema estructural que se agrava o mejora con políticas, no solo con nombres.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Las declaraciones de Federico Gutiérrez son un claro <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">abrebocas</span> de la campaña presidencial de 2026. Al usar el Congreso de Comerciantes como plataforma, ha elevado el tono de la confrontación política a niveles que exigen a la ciudadanía discernir entre la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">crítica fundamentada</span> y la <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">simple arenga electoral</span>. La democracia exige debate, pero la responsabilidad ética demanda que ese debate respete la verdad y evite la instrumentalización del dolor. El país espera menos polarización y más propuestas.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">¿Cree usted que este tipo de declaraciones ayudan a encontrar soluciones o solo aumentan la división en el país?</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><br></p>', 'public/images/blog/1759175001_fico-1140x570.jpg', 'Intermedia Colombia', 'published', 0, '2025-09-29 19:42:46', '2025-09-29 19:43:21', '', '', ''),
(8, '¿Quién protege a los protectores? El dilema de la seguridad en Colombia', 'quien-protege-a-los-protectores-el-dilema-de-la-seguridad-en-colombia', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El reciente evento en La Plata, Huila, donde *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">64 soldados fueron expulsados*</span> por cerca de 500 campesinos, ha puesto de manifiesto una cruda realidad y una pregunta inquietante que resuena en todo el país:<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\"> *si el Ejército es el encargado de velar por la seguridad de los colombianos, ¿quién vela por la de ellos*</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La situación, descrita por *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">el coronel Henry Herrera Arenas como un «secuestro» debido a la inmovilización forzada de los militares*,</span> revela una estrategia de los grupos armados ilegales para instrumentalizar a la población civil. Según la inteligencia militar, las comunidades fueron coaccionadas bajo amenazas de desplazamiento forzado y asesinatos selectivos. *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Esto nos obliga a mirar más allá de la confrontación superficial entre la población y los uniformados y a entender que, en este escenario, tanto los campesinos como los soldados son víctimas de una misma violencia*.</span></p><div class=\"adsb30\" style=\"margin: 12px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); text-align: center;\"></div><div class=\"adsb30\" style=\"margin: 12px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); text-align: center;\"></div><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Este tipo de *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">actos no solo humilla y desmoraliza a la Fuerza Pública*</span>, sino que también premia la delincuencia. Cuando los grupos ilegales logran sus objetivos al intimidar a las comunidades para que actúen en su nombre, se sienten más empoderados para seguir controlando territorios y ejerciendo su poder. *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">La llegada de 300 hombres de la Fuerza de Despliegue Rápido es una respuesta necesaria para restablecer el control territorial, pero la solución a largo plazo no puede ser solo militar*.</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Es fundamental que el Estado intervenga de manera integral en estas zonas. No basta con el despliegue de tropas; se requiere una presencia estatal que aborde las causas de la vulnerabilidad de las comunidades. *<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Esto incluye programas de desarrollo económico, acceso a educación, salud y justicia. Solo cuando las comunidades sientan que el Estado está genuinamente presente y es una alternativa viable a la coacción de los grupos armados, se romperá este ciclo perverso de instrumentalización.*</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: \"Droid Serif\", Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El caso de La Plata es un espejo de lo que ocurre en muchas otras regiones del país. Es una muestra de que la seguridad no es solo una cuestión de armamento y soldados, sino de confianza y legitimidad. Colombia debe enfrentar la incómoda verdad de que, en muchas de sus zonas rurales, <span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">*el poder lo ejercen quienes siembran el miedo. Es hora de que el Estado recupere esos territorios, no solo con la fuerza, sino también con la esperanza y el desarrollo. Porque solo así, los protectores podrán ser protegidos por una sociedad que confía en ellos.*</span></p>', 'public/images/blog/1759175075_ejer-1-832x570.jpg', 'Intermedia Colombia', 'published', 0, '2025-09-29 19:44:35', '2025-09-29 19:44:45', '', '', '');
INSERT INTO `blog_posts` (`id`, `title`, `slug`, `content`, `image`, `author`, `status`, `deleted`, `created_at`, `updated_at`, `seo_title`, `seo_description`, `seo_keywords`) VALUES
(9, 'Nariño se prepara para vivir el Mes del Turismo 2025', 'narino-se-prepara-para-vivir-el-mes-del-turismo-2025', '<p><div data-fusion-collection=\"features\" data-fusion-type=\"articleStructuredData/default\" style=\"box-sizing: border-box; color: rgb(35, 35, 35); font-family: sourcesans, sans-serif; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"></div></p><div class=\"cnt-txt\" style=\"box-sizing: border-box; outline: 0px; margin-top: 20px; color: rgb(35, 35, 35); font-family: sourcesans, sans-serif; font-size: 16px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; letter-spacing: normal; orphans: 2; text-align: start; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\"><p style=\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; font: 16px / 24px Poppins, Arial, \"Helvetica Neue\", Helvetica, sans-serif; outline: 0px; display: inline;\">El 27 de septiembre,<span> </span><b style=\"box-sizing: border-box; font-weight: bolder;\">Día Internacional del Turismo,<span> </span></b>inicia en<span> </span><b style=\"box-sizing: border-box; font-weight: bolder;\">Chachagüí<span> </span></b>la segunda edición del Mes del Turismo, con una agenda que integra a comunidades, empresarios, autoridades y academia para destacar la riqueza cultural y natural del departamento.</p><p style=\"box-sizing: border-box; margin: 15px 0px; padding: 0px; font: 16px / 24px Poppins, Arial, \"Helvetica Neue\", Helvetica, sans-serif;\">Diferentes actividades estratégicas buscan consolidar a Nariño como un destino competitivo y sostenible. Entre los eventos más destacados se encuentran la participación de Parques Nacionales Naturales en El corregimiento de El Encano, el Congreso de Medicina Interna ACMI en Pasto,<span> </span><b style=\"box-sizing: border-box; font-weight: bolder;\">iniciativas de agroturismo de la Universidad de Nariño, además de festivales, ferias y rutas turísticas</b><span> </span>en diferentes municipios del departamento además, la programación será una antesala de escenarios nacionales e internacionales como la Macro rueda de Negocios y Bioexpo 2025, que se desarrollarán en el departamento con la llegada de<span> </span><b style=\"box-sizing: border-box; font-weight: bolder;\">más de 70 mil visitantes.</b></p><p style=\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; font: 16px / 24px Poppins, Arial, \"Helvetica Neue\", Helvetica, sans-serif;\">La Directora administrativa de Turismo, Claudia Patricia Erazo Casabón, señaló que, “La primera experiencia del mes del Turismo, dejó grandes resultados, abrió puertas,<span> </span><a href=\"https://caracol.com.co/2024/10/04/mas-de-500-guias-turisticos-de-colombia-se-reunieron-en-pasto/\" target=\"_blank\" rel=\"noreferrer\" title=\"https://caracol.com.co/2024/10/04/mas-de-500-guias-turisticos-de-colombia-se-reunieron-en-pasto/\" style=\"box-sizing: border-box; background-color: transparent; text-decoration: none; color: rgb(191, 0, 0); border-bottom: 2px solid rgb(191, 0, 0);\">generó visibilidad y permitió que Nariño sea finalista de la Medalla al Mérito en Innovación Turística a nivel nacional.</a><span> </span>Este logro mostró que la iniciativa debe continuar, porque es motor de desarrollo, integración y paz”.</p><p style=\"box-sizing: border-box; margin: 0px 0px 15px; padding: 0px; font: 16px / 24px Poppins, Arial, \"Helvetica Neue\", Helvetica, sans-serif;\">La agenda del Mes del Turismo proyecta a Nariño como un territorio de oportunidades, que impulsa la economía para fortalecer la integración social y promover su sostenibilidad.</p></div>', 'public/images/blog/1759175412_05e846fb1fd49ece112980d5039f6d1a.webp', 'Intermedia Colombia', 'published', 0, '2025-09-29 19:50:12', '2025-09-29 19:50:22', '', '', ''),
(10, 'M&G Consultores empresariales confirma solides financiera del Acueducto y Alcantarillado de Popayán.', 'm-g-consultores-empresariales-confirma-solides-financiera-del-acueducto-y-alcantarillado-de-popayan', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La auditoría externa que llevó a cabo M&amp;G Consultores empresariales, una firma especializada con trayectoria nacional, estableció que AAPSA cuenta con fundamentos financieros sólidos que permiten afirmar su viabilidad financiera en el corto y mediano plazo.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">“De esta auditoría externa que se realizó sobre los resultados del año 2024, podemos resaltar que se logró mayor eficiencia en el recaudo, avanzamos principalmente en el recaudo de cartera difícil, en el comparativo financiero con el 2023, los Ingresos operacionales crecieron un 4,9 %, El EBITDA aumentó 30,5 %, reflejando mayor productividad operativa, la utilidad neta pasó de $987 millones a $2.435 millones, El endeudamiento se redujo 3,3 puntos porcentuales.</p><div class=\"adsb30\" style=\"margin: 12px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); text-align: center;\"></div><div class=\"adsb30\" style=\"margin: 12px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); text-align: center;\"></div><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">También establece la auditoria, que el recaudo sobre facturado: 88,51 %. Normalizado en 95,19, Flujos comprometidos: mejoraron de 8,57 a 5,80, Días de cartera: 64 días, dentro del rango óptimo, el endeudamiento está controlado y algo que es fundamental para la empresa es que no se evidencian riesgos que comprometan la continuidad del servicio” manifestó John Diego Parra Tobar, Gerente AAPSA.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El Acueducto y Alcantarillado de Popayán S. A. E.S.P. cerró 2024 con su mejor desempeño operativo de los últimos 5 años, según el informe entregado a la Superintendencia de Servicios Públicos. La entidad registró ingresos por $57.248 millones, un aumento real del 4,9 %, y un margen EBITDA histórico del 22,49 % ($12.874 millones); esto refleja una estructura operativa sólida, soportada por controles de gasto y optimización de ingresos tarifarios.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La empresa agradece a todos los habitantes de Popayán por su respaldo durante el 2024 y este primer semestre del año, reiteramos que se continua invirtiendo en las comunas y el sector rural para seguir llevando agua de calidad a los hogares, que hay transparencia en el manejo de los recursos y que en este gobierno se fortalece la empresa para que siga siendo pública.</p>', 'public/images/blog/1759183090_WhatsApp-Image-2025-06-12-at-07.36.19.jpeg', 'Intermedia Colombia', 'published', 0, '2025-09-29 21:58:10', '2025-09-29 21:58:10', '', '', ''),
(11, 'La Alcaldía de Popayán recibe tractor para impulsar el desarrollo agropecuario en el municipio', 'la-alcaldia-de-popayan-recibe-tractor-para-impulsar-el-desarrollo-agropecuario-en-el-municipio', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Como resultado de un convenio interadministrativo entre la Gobernación del Cauca y la Secretaría de Desarrollo Agroambiental y Fomento Económico (DAFE) de Popayán, se oficializó la entrega de un tractor equipado con ocho implementos agrícolas. Este recurso fortalecerá las capacidades técnicas y productivas del sector agropecuario en el municipio, beneficiando directamente a las comunidades campesinas. Con esta herramienta, ahora parte del banco de maquinaria del municipio, se busca reducir brechas tecnológicas y promover prácticas agrícolas más sostenibles en las zonas rurales.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">“<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Esta entrega representa un gran avance para el sector agropecuario de Popayán</span>,&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">tractor no solo será fundamental en los proyectos productivos, sino que también apoyará labores en viveros y otras iniciativas rurales. Este es un ejemplo de cómo la articulación con la Gobernación del Cauca nos permite llevar soluciones concretas que mejoran las condiciones de vida en el campo</span>”, afirmó Iván Darío Arturo Pabón, Secretario de DAFE.</p><div class=\"google-auto-placed ap_container\" style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); width: 750px; height: auto; clear: both; text-align: center;\"><ins data-ad-format=\"auto\" class=\"adsbygoogle adsbygoogle-noablate\" data-ad-client=\"ca-pub-4829843907633909\" data-adsbygoogle-status=\"done\" data-ad-status=\"unfilled\" style=\"margin: auto; padding: 0px; border: 0px; font: inherit; vertical-align: baseline; background-color: transparent; display: block; height: 0px; background-image: initial !important; background-position: initial !important; background-size: initial !important; background-repeat: initial !important; background-attachment: initial !important; background-origin: initial !important; background-clip: initial !important;\"><div id=\"aswift_4_host\" style=\"margin: 0px; padding: 0px; border: none; font: inherit; vertical-align: baseline; height: 0px; width: 750px; position: relative; visibility: visible; background-color: transparent; display: inline-block; overflow: hidden; opacity: 0;\"><iframe id=\"aswift_4\" name=\"aswift_4\" browsingtopics=\"true\" sandbox=\"allow-forms allow-popups allow-popups-to-escape-sandbox allow-same-origin allow-scripts allow-top-navigation-by-user-activation\" width=\"750\" height=\"0\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\" vspace=\"0\" hspace=\"0\" allowtransparency=\"true\" scrolling=\"no\" allow=\"attribution-reporting; run-ad-auction\" src=\"https://googleads.g.doubleclick.net/pagead/ads?gdpr=0&amp;client=ca-pub-4829843907633909&amp;output=html&amp;h=280&amp;adk=144910138&amp;adf=4248172323&amp;pi=t.aa~a.369024205~i.10~rp.4&amp;w=750&amp;fwrn=4&amp;fwrnh=100&amp;lmt=1759186103&amp;num_ads=1&amp;rafmt=1&amp;armr=3&amp;sem=mc&amp;pwprc=7807067007&amp;ad_type=text_image&amp;format=750x280&amp;url=https%3A%2F%2Fwww.caucaextremo.com%2Flocal%2Fla-alcaldia-de-popayan-recibe-tractor-para-impulsar-el-desarrollo-agropecuario-en-el-municipio%2F&amp;fwr=0&amp;pra=3&amp;rh=188&amp;rw=750&amp;rpe=1&amp;resp_fmts=3&amp;wgl=1&amp;fa=27&amp;uach=WyJXaW5kb3dzIiwiMTUuMC4wIiwieDg2IiwiIiwiMTQwLjAuNzMzOS4xMjgiLG51bGwsMCxudWxsLCI2NCIsW1siQ2hyb21pdW0iLCIxNDAuMC43MzM5LjEyOCJdLFsiTm90PUE_QnJhbmQiLCIyNC4wLjAuMCJdLFsiR29vZ2xlIENocm9tZSIsIjE0MC4wLjczMzkuMTI4Il1dLDBd&amp;abgtt=9&amp;dt=1759186103042&amp;bpp=7&amp;bdt=2272&amp;idt=-M&amp;shv=r20250925&amp;mjsv=m202509230101&amp;ptt=9&amp;saldr=aa&amp;abxe=1&amp;cookie=ID%3D10ab754ce0503ae9%3AT%3D1759184978%3ART%3D1759186064%3AS%3DALNI_MYgPhx2hjraAFgh0Ou95EV6pTtpng&amp;gpic=UID%3D000012961a477675%3AT%3D1759184978%3ART%3D1759186064%3AS%3DALNI_MZgPFb9MTQ7YADSPSK0N1EnmpCo-A&amp;eo_id_str=ID%3Dc9b3f443f534cd8c%3AT%3D1759184978%3ART%3D1759186064%3AS%3DAA-AfjbWzN1Fy8SXyjSZhB22xUiJ&amp;prev_fmts=0x0%2C726x280%2C345x280%2C726x280&amp;nras=2&amp;correlator=6495476634314&amp;frm=20&amp;pv=1&amp;u_tz=-300&amp;u_his=2&amp;u_h=768&amp;u_w=1366&amp;u_ah=720&amp;u_aw=1366&amp;u_cd=24&amp;u_sd=1&amp;dmc=8&amp;adx=106&amp;ady=1605&amp;biw=1351&amp;bih=633&amp;scr_x=0&amp;scr_y=0&amp;eid=31094857%2C42531705%2C95370627%2C95368094&amp;oid=2&amp;pvsid=8836216651210061&amp;tmod=1667625231&amp;uas=0&amp;nvt=1&amp;ref=https%3A%2F%2Fwww.caucaextremo.com%2F&amp;fc=1408&amp;brdim=0%2C0%2C0%2C0%2C1366%2C0%2C1366%2C720%2C1366%2C633&amp;vis=1&amp;rsz=%7C%7Cs%7C&amp;abl=NS&amp;fu=128&amp;bc=31&amp;bz=1&amp;td=1&amp;tdf=2&amp;psd=W251bGwsbnVsbCxudWxsLDNd&amp;nt=1&amp;pgls=CAEaBTYuOC4y~CAEQBRoGMy4yNy43&amp;ifi=5&amp;uci=a!5&amp;btvi=4&amp;fsb=1&amp;dtd=303\" data-google-container-id=\"a!5\" tabindex=\"0\" title=\"Advertisement\" aria-label=\"Advertisement\" data-load-complete=\"true\" data-google-query-id=\"CISJseSG_48DFfBTpAQdY8g1LQ\" style=\"margin: 0px; padding: 0px; font: inherit; vertical-align: baseline; max-width: none; left: 0px; position: absolute; top: 0px; width: 750px; height: 0px; min-height: auto; max-height: none; min-width: auto;\"></iframe></div></ins></div><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Dairo Sauca, supervisor del proyecto de mecanización de la Secretaría de Agricultura del Cauca, destacó las ventajas técnicas del equipo entregado:&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">“El tractor y sus implementos facilitarán enormemente el trabajo agrícola. Su uso permitirá reducir costos operativos, optimizar tiempos y mejorar las condiciones para los pequeños productores, quienes muchas veces enfrentan limitaciones tecnológicas”</span></p>', 'public/images/blog/1759186240_258.jpg', 'Ana Maria Daza', 'published', 0, '2025-09-29 22:50:40', '2025-09-29 22:50:40', '', '', ''),
(12, 'Es un hecho, Popayán se prepara para correr la Media Maratón de Popayán 2024', 'es-un-hecho-popayan-se-prepara-para-correr-la-media-maraton-de-popayan-2024', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La Administración Municipal en articulación con la Fundación Juancho Correlón, se preparan para la Media Maratón de Popayán 2024, un evento que se llevará a cabo el próximo domingo 22 de diciembre, a partir de las 6:00 a.m., en el Parque de Caldas. Habrá tres categorías 5K, 10K y 21K, con una premiación de más de $70 millones de pesos, que tienen como propósito promover la actividad física, crear un ambiente festivo para toda la familia y transmitir un mensaje de unidad a través del deporte. Las inscripciones fueron gratuitas y una vez habilitadas las inscripciones tuvieron una gran acogida obteniendo 4.000 participantes, donde muchos nos alcanzaron a realizar su proceso de inscripción, sin embargo, quienes deseen participar pueden acompañar esta experiencia.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El Secretario de Deporte, Luis Felipe Sánchez, expresó:&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">«Queremos que este evento sea una fiesta deportiva, una fiesta para la familia y sobre todo, un mensaje de paz para toda Colombia. Los estaremos esperando el domingo 22 de diciembre a las 6:00 a.m. en el Parque de Caldas, donde correremos 5K, 10K y 21K. Todos están cordialmente invitados, en esta gran jornada».</span></p><div class=\"google-auto-placed ap_container\" style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); width: 750px; height: auto; clear: both; text-align: center;\"><ins data-ad-format=\"auto\" class=\"adsbygoogle adsbygoogle-noablate\" data-ad-client=\"ca-pub-4829843907633909\" data-adsbygoogle-status=\"done\" data-ad-status=\"unfilled\" style=\"margin: auto; padding: 0px; border: 0px; font: inherit; vertical-align: baseline; background-color: transparent; display: block; height: 0px; background-image: initial !important; background-position: initial !important; background-size: initial !important; background-repeat: initial !important; background-attachment: initial !important; background-origin: initial !important; background-clip: initial !important;\"><div id=\"aswift_4_host\" style=\"margin: 0px; padding: 0px; border: none; font: inherit; vertical-align: baseline; height: 0px; width: 750px; position: relative; visibility: visible; background-color: transparent; display: inline-block; overflow: hidden; opacity: 0;\"><iframe id=\"aswift_4\" name=\"aswift_4\" browsingtopics=\"true\" sandbox=\"allow-forms allow-popups allow-popups-to-escape-sandbox allow-same-origin allow-scripts allow-top-navigation-by-user-activation\" width=\"750\" height=\"0\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\" vspace=\"0\" hspace=\"0\" allowtransparency=\"true\" scrolling=\"no\" allow=\"attribution-reporting; run-ad-auction\" src=\"https://googleads.g.doubleclick.net/pagead/ads?gdpr=0&amp;client=ca-pub-4829843907633909&amp;output=html&amp;h=280&amp;adk=144910138&amp;adf=4248172323&amp;pi=t.aa~a.369024205~i.10~rp.4&amp;w=750&amp;fwrn=4&amp;fwrnh=100&amp;lmt=1759186844&amp;num_ads=1&amp;rafmt=1&amp;armr=3&amp;sem=mc&amp;pwprc=7807067007&amp;ad_type=text_image&amp;format=750x280&amp;url=https%3A%2F%2Fwww.caucaextremo.com%2Flocal%2Fes-un-hecho-popayan-se-prepara-para-correr-la-media-maraton-de-popayan-2024%2F&amp;fwr=0&amp;pra=3&amp;rh=188&amp;rw=750&amp;rpe=1&amp;resp_fmts=3&amp;wgl=1&amp;fa=27&amp;uach=WyJXaW5kb3dzIiwiMTUuMC4wIiwieDg2IiwiIiwiMTQwLjAuNzMzOS4xMjgiLG51bGwsMCxudWxsLCI2NCIsW1siQ2hyb21pdW0iLCIxNDAuMC43MzM5LjEyOCJdLFsiTm90PUE_QnJhbmQiLCIyNC4wLjAuMCJdLFsiR29vZ2xlIENocm9tZSIsIjE0MC4wLjczMzkuMTI4Il1dLDBd&amp;abgtt=9&amp;dt=1759186844398&amp;bpp=2&amp;bdt=761&amp;idt=2&amp;shv=r20250925&amp;mjsv=m202509230101&amp;ptt=9&amp;saldr=aa&amp;abxe=1&amp;cookie=ID%3D10ab754ce0503ae9%3AT%3D1759184978%3ART%3D1759186592%3AS%3DALNI_MYgPhx2hjraAFgh0Ou95EV6pTtpng&amp;gpic=UID%3D000012961a477675%3AT%3D1759184978%3ART%3D1759186592%3AS%3DALNI_MZgPFb9MTQ7YADSPSK0N1EnmpCo-A&amp;eo_id_str=ID%3Dc9b3f443f534cd8c%3AT%3D1759184978%3ART%3D1759186592%3AS%3DAA-AfjbWzN1Fy8SXyjSZhB22xUiJ&amp;prev_fmts=0x0%2C345x280%2C726x280&amp;nras=2&amp;correlator=2324878681023&amp;frm=20&amp;pv=1&amp;u_tz=-300&amp;u_his=4&amp;u_h=768&amp;u_w=1366&amp;u_ah=720&amp;u_aw=1366&amp;u_cd=24&amp;u_sd=1&amp;dmc=8&amp;adx=106&amp;ady=1553&amp;biw=1351&amp;bih=633&amp;scr_x=0&amp;scr_y=0&amp;eid=31094917%2C95344791%2C95368094&amp;oid=2&amp;pvsid=2962491441341532&amp;tmod=1667625231&amp;uas=0&amp;nvt=1&amp;ref=https%3A%2F%2Fwww.caucaextremo.com%2Flocal%2Fla-alcaldia-de-popayan-recibe-tractor-para-impulsar-el-desarrollo-agropecuario-en-el-municipio%2F&amp;fc=1408&amp;brdim=0%2C0%2C0%2C0%2C1366%2C0%2C1366%2C720%2C1366%2C633&amp;vis=1&amp;rsz=%7C%7Cs%7C&amp;abl=NS&amp;fu=128&amp;bc=31&amp;bz=1&amp;td=1&amp;tdf=2&amp;psd=W251bGwsbnVsbCxudWxsLDNd&amp;nt=1&amp;pgls=CAEaBTYuOC4y~CAEQBRoGMy4yNy43&amp;ifi=5&amp;uci=a!5&amp;btvi=3&amp;fsb=1&amp;dtd=561\" data-google-container-id=\"a!5\" tabindex=\"0\" title=\"Advertisement\" aria-label=\"Advertisement\" data-load-complete=\"true\" data-google-query-id=\"CN20-sWJ_48DFVk4aAgd-eg8JA\" style=\"margin: 0px; padding: 0px; font: inherit; vertical-align: baseline; max-width: none; left: 0px; position: absolute; top: 0px; width: 750px; height: 0px; min-height: auto; max-height: none; min-width: auto;\"></iframe></div></ins></div><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Por su parte, Mario Casas Franco, gerente de la Asociación Juancho Correlón, destacó que, tras firmar el convenio con la Alcaldía de Popayán, se ha trabajado arduamente en la organización de este evento, cabe resaltar que el empresario tiene más de 24 años de experiencia organizando la Media Maratón de Cali y otros encuentros a nivel nacional.&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">“Los participantes previos serán automáticamente inscritos para esta edición. La inscripción para el público se agotó rápidamente, lo que refleja el éxito y la buena acogida de la Media Maratón de Popayán</span></p>', 'public/images/blog/1759187173_78.jpg', 'Ana Maria Daza', 'published', 0, '2025-09-29 23:06:13', '2025-09-29 23:06:13', '', '', ''),
(13, 'Popayán se mueve por el bienestar de sus comunidades: Jornada de limpieza en la quebrada La Monja', 'popayan-se-mueve-por-el-bienestar-de-sus-comunidades-jornada-de-limpieza-en-la-quebrada-la-monja', '<p class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span id=\"geom_inter_1734830151471_28_15\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">Con el propósito de mitigar los riesgos de inundación y proteger a los habitantes de las zonas aledañas a la quebrada La Monja, la Alcaldía de Popayán, liderada por el Alcalde Juan Carlos Muñoz Bravo, desarrolló una jornada de descolmatación y limpieza en las comunas 5 y 6 del municipio, beneficiando a las comunidades de los barrios Primero de Mayo, Calicanto, Los Comuneros, Sindical, entre otros.</span></p><p class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span id=\"geom_inter_1734830151471_39_16\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">Esta iniciativa, coordinada a través de la Oficina de Gestión del Riesgo y ejecutada por la Constructora Alpon S.A.S., tiene como objetivo retirar materiales sólidos y sedimentos arrastrados por el agua que impiden o reducen el cauce normal de las fuentes hídricas, no solo en la quebrada La Monja, sino también en La Cantera, La Chirría, Pubus, Dos Agüitas, Brazo Seco, Río Ejido y Río Molino.</span></p><div class=\"google-auto-placed ap_container\" style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51); width: 750px; height: auto; clear: both; text-align: center;\"><ins data-ad-format=\"auto\" class=\"adsbygoogle adsbygoogle-noablate\" data-ad-client=\"ca-pub-4829843907633909\" data-adsbygoogle-status=\"done\" data-ad-status=\"unfilled\" style=\"margin: auto; padding: 0px; border: 0px; font: inherit; vertical-align: baseline; background-color: transparent; display: block; height: 0px; background-image: initial !important; background-position: initial !important; background-size: initial !important; background-repeat: initial !important; background-attachment: initial !important; background-origin: initial !important; background-clip: initial !important;\"><div id=\"aswift_4_host\" style=\"margin: 0px; padding: 0px; border: none; font: inherit; vertical-align: baseline; height: 0px; width: 750px; position: relative; visibility: visible; background-color: transparent; display: inline-block; overflow: hidden; opacity: 0;\"><iframe id=\"aswift_4\" name=\"aswift_4\" browsingtopics=\"true\" sandbox=\"allow-forms allow-popups allow-popups-to-escape-sandbox allow-same-origin allow-scripts allow-top-navigation-by-user-activation\" width=\"750\" height=\"0\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\" vspace=\"0\" hspace=\"0\" allowtransparency=\"true\" scrolling=\"no\" allow=\"attribution-reporting; run-ad-auction\" src=\"https://googleads.g.doubleclick.net/pagead/ads?gdpr=0&amp;client=ca-pub-4829843907633909&amp;output=html&amp;h=280&amp;adk=144910138&amp;adf=615410430&amp;pi=t.aa~a.369024205~i.12~rp.4&amp;w=750&amp;fwrn=4&amp;fwrnh=100&amp;lmt=1759187227&amp;num_ads=1&amp;rafmt=1&amp;armr=3&amp;sem=mc&amp;pwprc=7807067007&amp;ad_type=text_image&amp;format=750x280&amp;url=https%3A%2F%2Fwww.caucaextremo.com%2Flocal%2Fpopayan-se-mueve-por-el-bienestar-de-sus-comunidades-jornada-de-limpieza-en-la-quebrada-la-monja%2F&amp;fwr=0&amp;pra=3&amp;rh=188&amp;rw=750&amp;rpe=1&amp;resp_fmts=3&amp;wgl=1&amp;fa=27&amp;uach=WyJXaW5kb3dzIiwiMTUuMC4wIiwieDg2IiwiIiwiMTQwLjAuNzMzOS4xMjgiLG51bGwsMCxudWxsLCI2NCIsW1siQ2hyb21pdW0iLCIxNDAuMC43MzM5LjEyOCJdLFsiTm90PUE_QnJhbmQiLCIyNC4wLjAuMCJdLFsiR29vZ2xlIENocm9tZSIsIjE0MC4wLjczMzkuMTI4Il1dLDBd&amp;abgtt=9&amp;dt=1759187227314&amp;bpp=2&amp;bdt=1330&amp;idt=-M&amp;shv=r20250925&amp;mjsv=m202509230101&amp;ptt=9&amp;saldr=aa&amp;abxe=1&amp;cookie=ID%3D10ab754ce0503ae9%3AT%3D1759184978%3ART%3D1759186592%3AS%3DALNI_MYgPhx2hjraAFgh0Ou95EV6pTtpng&amp;gpic=UID%3D000012961a477675%3AT%3D1759184978%3ART%3D1759186592%3AS%3DALNI_MZgPFb9MTQ7YADSPSK0N1EnmpCo-A&amp;eo_id_str=ID%3Dc9b3f443f534cd8c%3AT%3D1759184978%3ART%3D1759186592%3AS%3DAA-AfjbWzN1Fy8SXyjSZhB22xUiJ&amp;prev_fmts=0x0%2C726x280%2C345x280&amp;nras=2&amp;correlator=7019849411414&amp;frm=20&amp;pv=1&amp;u_tz=-300&amp;u_his=5&amp;u_h=768&amp;u_w=1366&amp;u_ah=720&amp;u_aw=1366&amp;u_cd=24&amp;u_sd=1&amp;dmc=8&amp;adx=106&amp;ady=1595&amp;biw=1351&amp;bih=633&amp;scr_x=0&amp;scr_y=0&amp;eid=95368094&amp;oid=2&amp;pvsid=222408349806302&amp;tmod=1667625231&amp;uas=0&amp;nvt=1&amp;ref=https%3A%2F%2Fwww.caucaextremo.com%2Flocal%2Fes-un-hecho-popayan-se-prepara-para-correr-la-media-maraton-de-popayan-2024%2F&amp;fc=1408&amp;brdim=0%2C0%2C0%2C0%2C1366%2C0%2C1366%2C720%2C1366%2C633&amp;vis=1&amp;rsz=%7C%7Cs%7C&amp;abl=NS&amp;fu=128&amp;bc=31&amp;bz=1&amp;td=1&amp;tdf=2&amp;psd=W251bGwsbnVsbCxudWxsLDNd&amp;nt=1&amp;pgls=CAEaBTYuOC4y~CAEQBRoGMy4yNy43&amp;ifi=5&amp;uci=a!5&amp;btvi=3&amp;fsb=1&amp;dtd=256\" data-google-container-id=\"a!5\" tabindex=\"0\" title=\"Advertisement\" aria-label=\"Advertisement\" data-google-query-id=\"CIOQuPyK_48DFThnHgIdPaEtzA\" data-load-complete=\"true\" style=\"margin: 0px; padding: 0px; font: inherit; vertical-align: baseline; max-width: none; left: 0px; position: absolute; top: 0px; width: 750px; height: 0px; min-height: auto; max-height: none; min-width: auto;\"></iframe></div></ins></div><p id=\"geom_inter_1734830155474_48_30\" class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span id=\"geom_inter_1734830151471_65_17\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">El Alcalde estuvo presente durante la jornada, realizando un recorrido por los alrededores de la quebrada para verificar de primera mano los avances de esta actividad, que desde hace más de cuatro años no se realizaba en la zona.&nbsp;<span id=\"geom_inter_1734830151471_74_18\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">“Hoy estamos cumpliéndole a la comunidad, mostrando que estamos siendo proactivos y propositivos frente a esto. Es una alianza con la prevención, con el trabajo mancomunado y&nbsp; con las comunidades de las comunas 5 y 6”</span>, destacó el mandatario<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">.</span></span></p><p id=\"geom_inter_1734830155472_41_29\" class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\"><span id=\"geom_inter_1734830154468_69_28\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Estamos terminando este tramo, son 2 km a lo largo de la quebrada. Arrancamos aquí en el puente de la gran victoria y terminamos en el puente de la 17. Este es un trabajo a conciencia, un trabajo muy bien realizado por la constructora que lo está haciendo, supervisado por la misma comunidad, la Oficina de Gestión del Riesgo y la Secretaría de infraestructura”</span>, explicó Jair Flórez</span><span lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">,&nbsp;</span><span id=\"geom_inter_1734830153482_82_22\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">&nbsp;Jefe de la Oficina Asesora de Gestión del Riesgo, quien además resaltó la pertinencia de estas acciones, pues a inicios de octubre, ante las fuertes lluvias, la quebrada se desbordó dejando más de 130 damnificados.<i style=\"margin: 0px; padding: 0px; border: 0px; font-variant: inherit; font-weight: inherit; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\"></i></span></p><p id=\"geom_inter_1734830155474_48_30\" class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span id=\"geom_inter_1734830151471_65_17\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\"></span></span></p><p class=\"x_MsoNormal\" style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span id=\"geom_inter_1734830153482_30_23\" lang=\"ES-CO\" style=\"margin: 0px; padding: 0px; border: 0px; font: inherit; vertical-align: baseline;\">De igual manera, los habitantes de la zona han reconocido lo valiosas que son estas jornadas de limpieza para evitar inundaciones y deslizamientos de tierra, impactando positivamente sobre su salud y bienestar.&nbsp;&nbsp;<span id=\"geom_inter_1734830153482_77_24\" style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">“Para nosotros es de mucha alegría saber que por primera vez gestión de riesgo hace una labor maravillosa en esta quebrada”</span>, comentó Olga Pineda, presidenta de la Junta de Acción Comunal del barrio Gran Victoria</span></p>', 'public/images/blog/1759187302_96-940x570.png', 'Ana Maria Daza', 'published', 0, '2025-09-29 23:08:22', '2025-09-29 23:08:22', '', '', '');
INSERT INTO `blog_posts` (`id`, `title`, `slug`, `content`, `image`, `author`, `status`, `deleted`, `created_at`, `updated_at`, `seo_title`, `seo_description`, `seo_keywords`) VALUES
(14, 'Institución Educativa Gabriela Mistral graduó a nuevos bachilleres', 'institucion-educativa-gabriela-mistral-graduo-a-nuevos-bachilleres', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">En una emotiva ceremonia,&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Institucion Educativa Gabriela Mistral culminó</span>&nbsp;un importante capítulo al graduar a nuevos bachilleres donde se encontraba Nelson Javier Escobar.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">La atmósfera de la&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Institucion Educativa Gabriela Mistral&nbsp;</span>se llenó de alegría y emoción, con graduandos que asistieron acompañados de familiares, quienes expresaban satisfacción por el exitoso cumplimiento de sus obligaciones académicas.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">Las palabras de los representantes estudiantiles resonaron con gratitud hacia profesores,&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">compañeros y padres, reconociendo el apoyo fundamental durante su trayectoria escolar.</span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">Las emoción se intensifica con los comentario de la madre de &nbsp;Nelson Javier , la señora &nbsp;Fernanda Montero</span>, quien elogió la contribución del colegio y sus profesores en la formación de sus hijo el cual tendrá como próxima meta ser Ingeniero de Sistemas.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\"></span></p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\"><span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">La ceremonia no solo reconoció a los mejores puntajes Icfes, a los puntuales y buenos amigos</span>, sino que también destacó otras características distintivas de los estudiantes a lo largo de su paso por la institución educativa</p>', 'public/images/blog/1759187447_2-1140x570.jpeg', 'Ana Maria Daza', 'published', 0, '2025-09-29 23:10:47', '2025-09-29 23:10:47', '', '', ''),
(15, 'Popayán: Conectada y a la Vanguardia', 'popayan-conectada-y-a-la-vanguardia', '<p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El reciente evento del Show Truck de EMTEL y Huawei en Popayán fue mucho más que una simple exhibición tecnológica; fue una declaración de intenciones. Al transformar el Parque Caldas en un epicentro de innovación, EMTEL no solo presentó sus servicios, sino que también reafirmó su compromiso con el progreso y la conectividad de la ciudad.</p><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">En un mundo donde la tecnología avanza a pasos agigantados, es fácil sentirse desconectado. Sin embargo, iniciativas como esta demuestran que la&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">transformación digital</span>&nbsp;no es un concepto abstracto, sino una realidad palpable que puede ser experimentada y comprendida por todos. La asistencia masiva y el entusiasmo de los participantes, desde niños hasta adultos mayores, son prueba de que existe una gran avidez por la tecnología y sus beneficios.</p><h3 style=\"margin: 1em 0px 0.5em; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; font-size: 1.563em; line-height: 1.4; font-family: Roboto, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(17, 17, 17); text-rendering: optimizelegibility;\">Más Allá de la Conectividad: Una Experiencia para la Comunidad</h3><p style=\"margin-right: 0px; margin-bottom: 1.25em; margin-left: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; text-rendering: optimizelegibility; color: rgb(51, 51, 51);\">El Show Truck no solo mostró productos, sino que también creó un espacio de&nbsp;<span style=\"margin: 0px; padding: 0px; border: 0px; font-style: inherit; font-variant: inherit; font-weight: 700; font-stretch: inherit; font-size: inherit; line-height: inherit; font-family: inherit; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline;\">interacción y aprendizaje</span>. La realidad virtual, las demostraciones en vivo y el asesoramiento personalizado permitieron a los ciudadanos tocar, sentir y vivir el futuro de las telecomunicaciones. La presencia del querido personaje Emtelito añadió un toque de cercanía y calidez, reforzando la idea de que EMTEL es una empresa que se preocupa por su comunidad y no solo por sus clientes</p>', 'public/images/blog/1759187775_WhatsApp-Image-2025-08-06-at-08.25.28-1140x570.jpeg', 'Ana Maria Daza', 'published', 0, '2025-09-29 23:16:15', '2025-09-29 23:16:15', '', '', ''),
(16, 'Juegos de Verano: Un Grito de Unidad y Equipo', 'juegos-de-verano-un-grito-de-unidad-y-equipo', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">En un mundo empresarial que a menudo se enfoca únicamente en metas y resultados, iniciativas como los&nbsp;</span><span style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-weight: 700; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51);\">Juegos de Verano EMTEL 2025</span><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">&nbsp;demuestran que el verdadero éxito reside en el capital humano. Más que una simple serie de competencias deportivas, estos juegos son un reflejo de una cultura corporativa que valora el bienestar y la cohesión de su equipo.</span></p><p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">El deporte, por naturaleza, es un catalizador para la unión. En las canchas sintéticas del Cubo, los roles jerárquicos se disuelven y lo que prevalece es el espíritu de equipo, la sana rivalidad y el apoyo mutuo.&nbsp;</span><span style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-weight: 700; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51);\">Damas y caballeros</span><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">&nbsp;de la familia EMTEL no solo competirán por el título, sino que, de manera más importante, reforzarán los lazos de amistad y camaradería que son esenciales para un ambiente de trabajo positivo y productivo.</span><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\"></span></p><p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">Los valores que se celebran en estos juegos –&nbsp;</span><span style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-weight: 700; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51);\">respeto, unión y trabajo en equipo</span><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">&nbsp;– no son exclusivos del ámbito deportivo. Son los mismos pilares que sustentan el crecimiento de la empresa día a día. Cada gol, cada punto, es una muestra del compromiso que cada empleado tiene no solo con el juego, sino con la visión compartida de hacer de EMTEL una empresa más fuerte y exitosa.</span><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\"></span></p>', 'public/images/blog/1759187901_WhatsApp-Image-2025-08-11-at-09.06.03-1065x570.jpeg', 'Ana Maria Daza', 'published', 0, '2025-09-29 23:18:21', '2025-09-29 23:18:21', '', '', '');
INSERT INTO `blog_posts` (`id`, `title`, `slug`, `content`, `image`, `author`, `status`, `deleted`, `created_at`, `updated_at`, `seo_title`, `seo_description`, `seo_keywords`) VALUES
(17, 'El valor de la conectividad en EMTEL', 'el-valor-de-la-conectividad-en-emtel', '<p><span style=\"color: rgb(51, 51, 51); font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif;\">En la era digital, la conectividad se ha convertido en una necesidad fundamental, no solo un lujo. En este sentido, la labor de empresas como&nbsp;</span><span style=\"margin: 0px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-variant-emoji: inherit; font-weight: 700; font-stretch: inherit; line-height: inherit; font-family: &quot;Droid Serif&quot;, Helvetica, Arial, sans-serif; font-optical-sizing: inherit; font-size-adjust: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; vertical-align: baseline; color: rgb(51, 51, 51);\"><a href=\"https://www.caucaextremo.com/regional/el-valor-de-la-conectividad-en-emtel/#\" class=\"google-anno\" data-google-vignette=\"false\" data-google-interstitial=\"false\" style=\"color-scheme: initial !important; forced-color-adjust: initial !important; mask: initial !important; math-depth: initial !important; position: initial !important; position-anchor: initial !important; text-size-adjust: initial !important; appearance: initial !important; color: initial !important; direction: inherit !important; font: initial !important; font-palette: initial !important; font-synthesis: initial !important; position-area: initial !important; text-orientation: inherit !important; text-rendering: initial !important; text-spacing-trim: initial !important; -webkit-font-smoothing: initial !important; -webkit-locale: initial !important; -webkit-text-orientation: initial !important; -webkit-writing-mode: initial !important; writing-mode: inherit !important; zoom: initial !important; accent-color: initial !important; place-content: initial !important; place-items: initial !important; place-self: initial